"""Ollama client wrapper — streams chat tokens from a local Ollama server."""

import os
from collections.abc import AsyncIterator

from ollama import AsyncClient


def get_ollama_host() -> str:
    return os.environ.get("OLLAMA_HOST", "http://localhost:11434")


def get_ollama_model() -> str:
    return os.environ.get("OLLAMA_MODEL", "qwen2.5:7b")


def make_client(host: str | None = None) -> AsyncClient:
    return AsyncClient(host=host or get_ollama_host())


async def stream_chat(
    message: str,
    *,
    model: str | None = None,
    host: str | None = None,
) -> AsyncIterator[str]:
    """Stream chat tokens from Ollama, yielding each content chunk."""
    client = make_client(host)
    response = await client.chat(
        model=model or get_ollama_model(),
        messages=[{"role": "user", "content": message}],
        stream=True,
    )
    async for chunk in response:
        content = chunk.get("message", {}).get("content", "")
        if content:
            yield content

(function () {
  "use strict";

  const messagesEl = document.getElementById("messages");
  const emptyState = document.getElementById("empty-state");
  const chatForm = document.getElementById("chat-form");
  const chatInput = document.getElementById("chat-input");
  const sendBtn = document.getElementById("send-btn");

  let socket = null;
  let currentAssistantEl = null;

  function buildWebSocket() {
    const proto = location.protocol === "https:" ? "wss" : "ws";
    const url = proto + "://" + location.host + "/ws/chat/";
    socket = new WebSocket(url);

    socket.onopen = function () {
      console.log("WebSocket connected");
    };

    socket.onmessage = function (event) {
      const data = JSON.parse(event.data);
      handleMessage(data);
    };

    socket.onclose = function () {
      console.log("WebSocket closed — reconnecting in 1s");
      setTimeout(buildWebSocket, 1000);
    };

    socket.onerror = function () {
      socket.close();
    };
  }

  function handleMessage(data) {
    if (data.type === "start") {
      emptyState.style.display = "none";
      currentAssistantEl = document.createElement("div");
      currentAssistantEl.className =
        "assistant-msg bg-gray-800 rounded-lg p-3 whitespace-pre-wrap";
      messagesEl.appendChild(currentAssistantEl);
      messagesEl.scrollTop = messagesEl.scrollHeight;
    } else if (data.type === "token" && currentAssistantEl) {
      currentAssistantEl.textContent += data.content;
      messagesEl.scrollTop = messagesEl.scrollHeight;
    } else if (data.type === "end") {
      currentAssistantEl = null;
    } else if (data.type === "error") {
      const errEl = document.createElement("div");
      errEl.className = "text-red-400 p-3";
      errEl.textContent = data.content;
      messagesEl.appendChild(errEl);
      currentAssistantEl = null;
    }
  }

  function addUserMessage(text) {
    emptyState.style.display = "none";
    const el = document.createElement("div");
    el.className =
      "user-msg bg-blue-700 rounded-lg p-3 ml-auto max-w-[80%] whitespace-pre-wrap";
    el.textContent = text;
    messagesEl.appendChild(el);
    messagesEl.scrollTop = messagesEl.scrollHeight;
  }

  chatForm.addEventListener("submit", function (e) {
    e.preventDefault();
    const text = chatInput.value.trim();
    if (!text) return;
    addUserMessage(text);
    chatInput.value = "";

    if (socket && socket.readyState === WebSocket.OPEN) {
      socket.send(JSON.stringify({ message: text }));
    }
  });

  buildWebSocket();
})();

